import { useEffect, useRef, useState } from "react";
import type { UserData } from "../../utils/dataTypesUtils";
import type { AddOrBuyProductProps } from "../../utils/propsUtils";
import { userFontSemibold } from "../../utils/stylingUtils";
import { useProducts } from "../customHooks/useProducts";
import { useEntityActions } from "../customHooks/useEntityActions";
import { AlertCircle} from "lucide-react";
import Modal, { type ModalHandle } from "./DeleteModal";
import { host, httpMethod } from "../../utils/utils";
import AvailableProducts from "../overviews/AvailableProducts";

export default function BuyProduct({
  trader: user,
  onSuccess,
}: AddOrBuyProductProps<UserData>) {
  const successModalRef = useRef<ModalHandle>(null);
  const confirmModalRef = useRef<ModalHandle>(null);
  const { products, loading, fetchProducts } = useProducts();
  const [selectedProducts, setSelectedProducts] = useState<Map<string, number>>(
    new Map()
  );
  const [errors, setErrors] = useState<Map<string, string>>(new Map());
  const { resetActions, resetNestedView } = useEntityActions();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [activeTab, setActiveTab] = useState<"available" | "request">(
    "available"
  );

  useEffect(() => {
    fetchProducts();
  }, [fetchProducts]);

  const calculateTotal = (): number => {
    let total = 0;
    selectedProducts.forEach((quantity, productId) => {
      const product = products.find((p) => p.id === productId);
      if (product && quantity > 0) {
        total += product.price * quantity;
      }
    });
    return total;
  };

  const totalCost = calculateTotal();
  const remainingBalance = user.balance - totalCost;
  const hasInsufficientFunds = remainingBalance < 0;

  const toggleProduct = (productId: string) => {
    setSelectedProducts((prev) => {
      const newMap = new Map(prev);
      if (newMap.has(productId)) {
        newMap.delete(productId);
        setErrors((prevErrors) => {
          const newErrors = new Map(prevErrors);
          newErrors.delete(productId);
          return newErrors;
        });
      } else {
        newMap.set(productId, 1);
      }
      return newMap;
    });
  };

  const updateQuantity = (productId: string, quantity: number) => {
    const product = products.find((p) => p.id === productId);
    if (!product) return;

    setSelectedProducts((prev) => {
      const newMap = new Map(prev);
      if (quantity > 0) {
        newMap.set(productId, quantity);
      } else {
        newMap.delete(productId);
      }
      return newMap;
    });

    setErrors((prev) => {
      const newErrors = new Map(prev);
      if (quantity > product.quantity) {
        newErrors.set(productId, `Only ${product.quantity} available`);
      } else {
        newErrors.delete(productId);
      }
      return newErrors;
    });
  };

  const handleConfirm = async () => {
    const productsToAdd = Array.from(selectedProducts.entries()).map(
      ([productId, quantity]) => ({
        "product-id": productId,
        quantity,
      })
    );

    setIsSubmitting(true);

    try {
      const response = await fetch(`${host}/traders-products/channel-a`, {
        method: httpMethod.POST,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          products: productsToAdd,
          "user-id": user.id,
        }),
      });

      if (response.ok) {
        const data = await response.json();
        console.log("Success: ", data.Message);

        confirmModalRef.current?.close();

        if (onSuccess) {
          await onSuccess();
        }

        successModalRef.current?.open();
      } else {
        const errorData = await response.json();
        alert(errorData.error || "Failed to add products");
        successModalRef.current?.close();
      }
    } catch (err) {
      alert(`Error: ${err instanceof Error ? err.message : String(err)}`);
      successModalRef.current?.close();
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleSubmit = () => {
    if (hasInsufficientFunds || errors.size > 0 || selectedProducts.size === 0)
      return;
    confirmModalRef.current?.open();
  };

  const isSubmitDisabled =
    loading ||
    selectedProducts.size === 0 ||
    hasInsufficientFunds ||
    errors.size > 0;

  return (
    <div className="space-y-6">
      <Modal
        ref={successModalRef}
        onConfirm={() => {
          successModalRef.current?.close();
          resetNestedView();
        }}
        confirmLabel="Close"
        showActions={true}
        cancelClassName="hidden"
        confirmClassName="px-6 py-3 bg-green-600 hover:bg-green-500 rounded border-2 border-green-400 transition-all duration-200 hover:shadow-lg hover:shadow-green-400/50 text-white font-semibold"
        dialogClassName="backdrop:bg-black/80 bg-gray-800 border-2 border-green-500 rounded-lg p-8 shadow-2xl shadow-green-500/50 max-w-2xl w-full"
      >
        {/* <SuccessProductAddingModal
          trader={trader}
          selectedProducts={selectedProducts}
          totalCost={totalCost}
          remainingBalance={remainingBalance}
        /> */}
        <h1>Some modal 3</h1>
      </Modal>

      {/* Confirmation Modal */}
      <Modal
        ref={confirmModalRef}
        onConfirm={handleConfirm}
        onCancel={() => confirmModalRef.current?.close()}
        confirmLabel={isSubmitting ? "Processing..." : "Confirm Purchase"}
        cancelLabel="Review Again"
        confirmClassName="px-6 py-3 bg-purple-600 hover:bg-purple-500 rounded border-2 border-purple-400 transition-all duration-200 hover:shadow-lg hover:shadow-purple-400/50 text-white font-semibold"
        cancelClassName="px-6 py-3 bg-gray-700 hover:bg-gray-600 rounded border-2 border-gray-600 transition-all duration-200 text-purple-300 font-semibold"
        dialogClassName="backdrop:bg-black/80 bg-gray-800 border-2 border-purple-500 rounded-lg p-8 shadow-2xl shadow-purple-500/50 max-w-3xl w-full"
      >
        <h1>Some modal</h1>
        {/* <ConfirmationModal
        //   trader={trader}
          selectedProducts={selectedProducts}
          totalCost={totalCost}
          remainingBalance={remainingBalance}
          products={products}
        /> */}
      </Modal>
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-purple-400 mb-2">
          Buy Products
        </h1>
        <p className="text-xl text-gray-300">
          <span className={userFontSemibold}>User:</span> {user.name}
        </p>
      </div>

      {/* Balance Summary Card */}
      <div className="bg-gray-800 border-2 border-purple-400 rounded-lg p-6 mb-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-center">
          <div>
            <p className="text-sm text-gray-400 mb-1">Current Balance</p>
            <p className="text-2xl font-bold text-green-400">
              ${user.balance.toFixed(2)}
            </p>
          </div>
          <div>
            <p className="text-sm text-gray-400 mb-1">Total Cost</p>
            <p className="text-2xl font-bold text-yellow-400">
              -${totalCost.toFixed(2)}
            </p>
          </div>
          <div>
            <p className="text-sm text-gray-400 mb-1">Remaining Balance</p>
            <p
              className={`text-2xl font-bold ${
                hasInsufficientFunds ? "text-red-500" : "text-green-400"
              }`}
            >
              ${remainingBalance.toFixed(2)}
            </p>
          </div>
        </div>

        {hasInsufficientFunds && (
          <div className="mt-4 flex items-center gap-2 px-4 py-3 bg-red-900/30 border border-red-500 rounded text-red-300">
            <AlertCircle size={20} />
            <span className="font-semibold">
              Insufficient Funds! Reduce quantities or remove products.
            </span>
          </div>
        )}
      </div>
      <div className="flex gap-2 border-b-2 border-purple-500">
        <button
          onClick={() => setActiveTab("available")}
          className={`px-6 py-3 font-semibold transition-all ${
            activeTab === "available"
              ? "text-purple-300 border-b-4 border-purple-400 -mb-0.5"
              : "text-gray-400 hover:text-purple-300"
          }`}
        >
          🛒 Available Products
          <span className="ml-2 px-2 py-1 bg-green-600 rounded text-white text-xs">
            In Stock
          </span>
        </button>
        <button
          onClick={() => setActiveTab("request")}
          className={`px-6 py-3 font-semibold transition-all ${
            activeTab === "request"
              ? "text-purple-300 border-b-4 border-purple-400 -mb-0.5"
              : "text-gray-400 hover:text-purple-300"
          }`}
        >
          📦 Request Items
          <span className="ml-2 px-2 py-1 bg-yellow-600 rounded text-white text-xs">
            Not Listed
          </span>
        </button>
      </div>

      {/* Content */}
      <div className="bg-gray-800 border-2 border-purple-500 rounded-lg p-8 shadow-2xl shadow-purple-500/50">
        {activeTab === "available" ? (
          <AvailableProducts user={user} products={products} />
        ) : (
          <RequestItems user={user} />
        )}
      </div>
    </div>
  );
}
